+            this.ws.send(JSON.stringify({
+                jsonrpc: '2.0',
+                id,
+                method,
+                params: params || {},
+            }));
+        });
+    }
+
+    async send(message) {
+        return this.request(message.method, message.params);
+    }
+
+    onMessage(handler) {
+        this.messageHandlers.push(handler);
+    }
+
+    async disconnect() {
+        this.connected = false;
+        if (this.ws) {
+            this.ws.close();
+            this.ws = null;
+        }
+    }
